public class PriceCalculator
{
    public decimal CalculateTotal(decimal unitPrice, int quantity)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(unitPrice);
        ArgumentOutOfRangeException.ThrowIfNegative(quantity);
        return unitPrice * quantity;
    }

    public decimal ApplyDiscount(decimal total, decimal discountPercent)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(total);
        if (discountPercent < 0 || discountPercent > 100)
            throw new ArgumentOutOfRangeException(nameof(discountPercent));
        return total * (1 - discountPercent / 100m);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new PriceCalculator();

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 10.00, DisplayName = "Single item")]
    [DataRow(10.00, 5, 50.00, DisplayName = "Multiple items")]
    [DataRow(0.00, 10, 0.00, DisplayName = "Zero price")]
    [DataRow(10.00, 0, 0.00, DisplayName = "Zero quantity")]
    [DataRow(19.99, 3, 59.97, DisplayName = "Fractional price")]
    [DataRow(0.01, 1, 0.01, DisplayName = "Minimum price")]
    public void CalculateTotal_ReturnsExpected(
        double unitPrice, int quantity, double expected)
    {
        var result = _sut.CalculateTotal((decimal)unitPrice, quantity);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, DisplayName = "Negative price throws")]
    [DataRow(10.00, -1, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_InvalidInput_Throws(double unitPrice, int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.CalculateTotal((decimal)unitPrice, quantity));
    }

    // --- ApplyDiscount: DynamicData for complex/reusable datasets ---

    [TestMethod]
    [DynamicData(nameof(DiscountCases), DynamicDataSourceType.Method,
        DynamicDataDisplayName = nameof(GetDiscountDisplayName))]
    public void ApplyDiscount_ReturnsExpected(
        decimal total, decimal discountPercent, decimal expected)
    {
        var result = _sut.ApplyDiscount(total, discountPercent);

        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> DiscountCases()
    {
        yield return [100m, 0m, 100.00m];     // No discount
        yield return [100m, 10m, 90.00m];      // 10% off
        yield return [100m, 50m, 50.00m];      // Half off
        yield return [100m, 100m, 0.00m];      // Full discount
        yield return [59.97m, 15m, 50.9745m];  // Fractional result
        yield return [0m, 25m, 0m];            // Zero total
    }

    public static string GetDiscountDisplayName(
        MethodInfo _, object[] data) =>
        $"Total={data[0]}, Discount={data[1]}% → {data[2]}";

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidInput_Throws(
        decimal total, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.ApplyDiscount(total, discountPercent));
    }

    private static IEnumerable<object[]> InvalidDiscountCases()
    {
        yield return [-10m, 10m];   // Negative total
        yield return [100m, -5m];   // Negative discount
        yield return [100m, 101m];  // Discount > 100%
    }
}

